import React, { useEffect, useState } from "react";
import axios from "axios";
import "./Home.css";

function MyPredictionHistory() {
  const [history, setHistory] = useState([]);

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));

    axios
      .get(`http://localhost:5001/history/${user.email}`)
      .then((res) => setHistory(res.data))
      .catch((err) => console.log(err));
  }, []);

  return (
    <div className="history-container">

      <h1 className="main-title">💼 ECS Salary Prediction Center</h1>

      <div className="stats-box">
        <h3>Total Predictions</h3>
        <p>{history.length}</p>
      </div>

      <h2 className="section-title">Recent Predictions</h2>

      <div className="history-grid">
        {history.length > 0 ? (
          history.slice(0, 6).map((item, index) => (
            <div className="history-card" key={index}>
              <p><b>📅 Date:</b> {new Date(item.createdAt).toLocaleDateString()}</p>
              <p><b>⏰ Time:</b> {new Date(item.createdAt).toLocaleTimeString()}</p>
              <p><b>💼 Role:</b> {item.JobRole}</p>
              <p><b>📊 Experience:</b> {item.Experience} yrs</p>
              <p className="salary">₹ {item.salary}</p>
            </div>
          ))
        ) : (
          <p className="no-data">No predictions yet</p>
        )}
      </div>
    </div>
  );
}

export default MyPredictionHistory;
